mapper.update:
UPDATE ELIB_BESTBOOK SET
	book_idx = #{book_idx}
WHERE
	bestbook_idx = #{bestbook_idx}

mapper.select:
${pagingTop}
SELECT
	a.book_idx, a.book_code, a.book_name, a.author_name, a.book_pubname, a.book_image,
	a.book_pubdt, a.book_regdt, a.add_date, a.use_yn, b.book_info, a.type

${pagingBottom}

mapper.update:
UPDATE ELIB_CATEGORY_BESTBOOK SET
	print_seq = #{print_seq}
WHERE
	book_code = #{book_code}
AND parent_id = #{parent_id}

mapper.select:
SELECT COUNT(*) AS cnt
FROM ELIB_CATEGORY_BESTBOOK
WHERE book_code = #{book_code}
AND parent_id = #{parent_id}
